"""Python-binding coverage for the native LAMMPS force-field reader.

The parsing/unit logic is exercised in Rust (``ff::forcefield::readers::lammps``);
these tests only assert the PyO3 surface — that ``read_lammps_forcefield`` /
``read_lammps_forcefield_str`` yield the rich Python :class:`ForceField` (with the
FFI capsule a consumer like molpack resolves) and that errors map to ``ValueError``.
"""

import pytest

import molrs

# Values copied from a real GAFF2 PEO ``*.ff`` (the molpack-paper figure-5 melt).
_FF = """\
# LAMMPS force field generated by molpy
pair_style lj/cut/coul/long 10.0 10.0
pair_coeff c3 c3 0.107800 3.397710
pair_coeff oh oh 0.093000 3.242871

bond_style harmonic
bond_coeff c3-c3 228.890000 1.535400

angle_style harmonic
angle_coeff c3-c3-oh 76.790000 109.660000

dihedral_style fourier
dihedral_coeff c3-c3-oh-ho 1 0.060000 3 0.000000
"""


def test_read_lammps_forcefield_str_yields_python_forcefield():
    ff = molrs.read_lammps_forcefield_str(_FF)
    # Rich Python ForceField (shadow), not the bare PyO3 core.
    assert type(ff).__module__ == "molrs.forcefield"
    # The FFI capsule a consumer (molpack relaxer) resolves zero-copy.
    assert hasattr(ff, "_ffi_forcefield_capsule")


def test_lammps_units_pass_through_binding():
    ff = molrs.read_lammps_forcefield_str(_FF)
    # LAMMPS harmonic K(=228.89) → molrs k = 2K = 457.78 (½k form); r0 unchanged.
    bond = ff.get_style("bond", "harmonic")
    bt = bond.get_type_by_name("c3-c3")
    assert bt.params["k"] == pytest.approx(457.78)
    assert bt.params["r0"] == pytest.approx(1.5354)
    # angle theta0 stays in degrees; pair ε/σ pass through.
    angle = ff.get_style("angle", "harmonic")
    at = angle.get_type_by_name("c3-c3-oh")
    assert at.params["theta0"] == pytest.approx(109.66)
    lj = ff.get_style("pair", "lj/cut")
    assert lj.get_type_by_name("c3").params["epsilon"] == pytest.approx(0.1078)


def test_read_lammps_forcefield_from_path(tmp_path):
    p = tmp_path / "melt.ff"
    p.write_text(_FF)
    ff = molrs.read_lammps_forcefield(str(p))
    assert len(ff.get_style("dihedral", "fourier").types) == 1


def test_unknown_keyword_maps_to_value_error():
    with pytest.raises(ValueError):
        molrs.read_lammps_forcefield_str("mystery_style foo\n")
